  1→/**
  2→ * End-to-end API tests for Claude Usage Leaderboard
  3→ *
  4→ * Run: npm test
  5→ * Requires: local dev server running (npm run dev) OR test against production
  6→ *
  7→ * Usage:
  8→ *   API_BASE=http://localhost:8787 npm test     # local dev
  9→ *   API_BASE=https://leaderboard.magizhan.work npm test  # production (needs auth)
 10→ */
 11→
 12→const API_BASE = process.env.API_BASE || 'http://localhost:8787';
 13→const TEST_USER = `_test_user_${Date.now()}`;
 14→const TEST_TEAM = 'NY';
 15→
 16→let testUserId = null;
 17→let passed = 0;
 18→let failed = 0;
 19→const failures = [];
 20→
 21→// ============================================================
 22→// Helpers
 23→// ============================================================
 24→
 25→async function api(path, method = 'GET', body = null) {
 26→  const opts = { method, headers: {} };
 27→  if (body) {
 28→    opts.headers['Content-Type'] = 'application/json';
 29→    opts.body = JSON.stringify(body);
 30→  }
 31→  const res = await fetch(`${API_BASE}${path}`, opts);
 32→  const data = await res.json().catch(() => null);
 33→  return { status: res.status, data };
 34→}
 35→
 36→function assert(condition, message) {
 37→  if (condition) {
 38→    passed++;
 39→    console.log(`  ✓ ${message}`);
 40→  } else {
 41→    failed++;
 42→    failures.push(message);
 43→    console.log(`  ✗ ${message}`);
 44→  }
 45→}
 46→
 47→function assertEq(actual, expected, message) {
 48→  assert(actual === expected, `${message} (expected: ${expected}, got: ${actual})`);
 49→}
 50→
 51→function assertApprox(actual, expected, tolerance, message) {
 52→  assert(Math.abs(actual - expected) <= tolerance, `${message} (expected: ~${expected}, got: ${actual})`);
 53→}
