 59→async function testUserCRUD() {
 60→  console.log('\n▸ User CRUD');
 61→
 62→  // Create user
 63→  const { status, data } = await api('/api/users', 'POST', {
 64→    name: TEST_USER, team: TEST_TEAM,
 65→  });
 66→  assertEq(status, 200, 'Create user returns 200');
 67→  assert(data.id && data.id.startsWith('u_'), 'User ID has correct format');
