 83→
 84→  // Invalid team defaults to NC
 85→  const badTeam = await api('/api/users', 'POST', {
 86→    name: `_test_badteam_${Date.now()}`, team: 'INVALID',
 87→  });
 88→  assertEq(badTeam.data.team, 'NC', 'Invalid team defaults to NC');
