104→async function testMonotonicIncrease() {
105→  console.log('\n▸ Usage — monotonic increase within session');
106→
107→  // Send higher value — should accept
108→  const higher = await api('/api/usage', 'POST', {
109→    name: TEST_USER, sessionPct: 15, weeklyPct: 25, source: 'extension',
