111→  assertEq(higher.data.sessionPct, 15, 'Higher session % accepted');
112→  assertEq(higher.data.weeklyPct, 25, 'Higher weekly % accepted');
113→
114→  // Send lower value within same session — should keep higher (monotonic)
115→  const lower = await api('/api/usage', 'POST', {
116→    name: TEST_USER, sessionPct: 14, weeklyPct: 24, source: 'extension',
117→  });
118→  assertEq(lower.data.sessionPct, 15, 'Lower session % rejected (monotonic)');
