122→async function testSessionReset() {
123→  console.log('\n▸ Usage — session reset detection');
124→
125→  // Set a high session value with a reset time in the past (expired session)
126→  const pastReset = new Date(Date.now() - 60000).toISOString(); // 1 min ago
127→  await api('/api/usage', 'POST', {
128→    name: TEST_USER, sessionPct: 30, weeklyPct: 40, source: 'extension',
129→    sessionResetsAt: pastReset,
130→  });
131→
132→  // Drop within expired session — should be accepted
133→  const reset = await api('/api/usage', 'POST', {
134→    name: TEST_USER, sessionPct: 4, weeklyPct: 42, source: 'extension',
135→  });
136→  assertEq(reset.data.sessionPct, 4, 'Session reset accepted (expired timer + drop)');
137→  assert(reset.data.weeklyPct >= 42, 'Weekly preserved/increased after session reset');
138→
139→  // Drop within active session — should be REJECTED (monotonic)
140→  const futureReset = new Date(Date.now() + 3600000).toISOString(); // 1 hr from now
141→  await api('/api/usage', 'POST', {
142→    name: TEST_USER, sessionPct: 20, weeklyPct: 45, source: 'extension',
143→    sessionResetsAt: futureReset,
144→  });
145→  const rejected = await api('/api/usage', 'POST', {
146→    name: TEST_USER, sessionPct: 5, weeklyPct: 45, source: 'extension',
147→  });
148→  assertEq(rejected.data.sessionPct, 20, 'Session drop rejected within active session');
149→}
