160→  });
161→
162→  // Both drop with expired timers — should be accepted
163→  const reset = await api('/api/usage', 'POST', {
164→    name: TEST_USER, sessionPct: 2, weeklyPct: 2, source: 'extension',
165→  });
166→  assertEq(reset.data.sessionPct, 2, 'Session accepted after weekly reset');
